const ItemView  = ({ itm, updObs, idKey, update, rmv, index }) => {
	
	const copyToClpb  =  (v)  => {

		copyToClipboard(v);
	};

	const updActive =  (e) => {
		if(getStore("addressItemActive") !== idKey){
			e.stopPropagation();
			e.preventDefault();
			updStore("addressItemActive",idKey);
			updObs(gen16CodeId());
		}
	}

	


	const _updItm  =  (v)  => {
		
		update(v,idKey)
	};

	const openUpdView =  () => {

		updStore(frmNm, itm);
		updStore(frmNm+"_bck", JSON.parse(JSON.stringify(itm)));
		

		let modal_data = {};
		modal_data["zIndex"] = 450;
		modal_data["height"] = "80vh";
		// data['observeResize']=true;
		modal_data["props"] = { minHeight: "1vh", overlay: true };
		modal_data["content"] = 
			<UpdateItemView confirm={_updItm} />
		OpenModal(modal_data);
	}

	const confirmDelete =  (v)  => {
		rmv(idKey)
	};



	const OpenDeleteAlert =  () => {
		let lastTimeCallModal = getStore("lastTimeCallModal") || 0;
		if(Date.now() > lastTimeCallModal){
			updStore("lastTimeCallModal", Date.now()+320);
			
			let modaldata = {};
			modaldata["zIndex"] = 450;
			modaldata["height"] = "40vh";
			// data['observeResize']=true;
			modaldata["props"] = { minHeight: "1vh", overlay: true, closeEvent: ()=>{}  };
			modaldata["content"] = <DeleteAlert
				confirm={confirmDelete}
				lbl_p={"Eliminar Direccion"} 
				lbl_span={"Una vez eliminado no podra ser recuperado"}
			/>
			OpenModal(modaldata);
		}
	}


	let isActive = getStore("addressItemActive") === idKey;

	return (
		<div   className={`client_item_box gWXAaj jlytmu ${isActive?"active":""}`} onClick={updActive}>
			
			{isActive?
			<div className={"menu_icon_acc _dsplFlx"}>
				<div className="flexSpace"/>
				<div  className="icon_action"	onClick={openUpdView}>
					<Svg name={"outline_edit"}	/>
				</div>
				<div  className="icon_action"	onClick={OpenDeleteAlert}>
					<Svg name={"outline_delete"}	/>
				</div>
						
			</div>:null}
			<div className="_dsplFlx " >
							<div className="_dsplFlx dtls">
								
								<div className="lbl_h_dtls">
								Place of Entry: 
								</div>
								<div className="lbl_dtls" onClick={()=>copyToClpb(itm?.placeOfEntry)}>
									{itm?.placeOfEntry}
								</div>
							</div>
						</div>
						<div className="_dsplFlx dtls">
							<div className="lbl_h_dtls">
							Date of Entry: 
							</div>
							
							<div className="lbl_dtls" onClick={()=>copyToClpb(parseDateMMDDYYYY(itm?.dateOfEntry))}>
								{parseDate(itm?.dateOfEntry)}
							</div>
						</div>

						<div className="_dsplFlx dtls">
							<div className="lbl_h_dtls">
							Date Left: 
							</div>
							<div className="lbl_dtls" onClick={()=>copyToClpb(parseDateMMDDYYYY(itm?.dateOfLeft))}>
								{parseDate(itm?.dateOfLeft)}
							</div>
						</div>						
						<div className="_dsplFlx dtls">
							<div className="lbl_h_dtls">
								Status: 
							</div>
							<div className="lbl_dtls" onClick={()=>copyToClpb(itm?.status)}>
								{itm?.status}
							</div>
						</div>
					
		</div>
	)
}





