const UpdateItemView  = ({ data,  itm, active, confirm }) => {
	const [obs, set_obs] = useState(1);

	
	
	
	const updFrm = (f, v, k) => {
		let frm2 = getStore(frmNm) || {};
		if(k){
			if( !frm2[k]){
				frm2[k] = {};
			}
			frm2[k][f] = v;
		}else{
			frm2[f] = v;
		}
		updStore(frmNm, frm2);
		
		set_obs(gen16CodeId())
	};


	const print  = async ()  => {
		let ffm = getStore(frmNm);
		confirm && confirm(ffm);
		close();
	};





	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID})
	}


	let flds = [
		"dateOfEntry", "status", "dateOfLeft", "placeOfEntry"
	]

	let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )


	return(
		<div style={{
			maxHeight: "80vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					Actualizar Entrada al Pais
				</p>
				<div className="flexSpace"/>
				
			</div>
			
			
			

		
			<div className="_dsplFlx spaceAround flxWrp" style={{margin:"30px 0px 0 0"}}>
				<TextInput  
					init={getStore(frmNm)?.["placeOfEntry"]} 
					label={"Place of Entry"} 
					width={460} 
					updChanges={(e)=>updFrm("placeOfEntry",e)}
				/>
				
			</div>
			<div className="_dsplFlx spaceAround flxWrp"> 
				<TextInput 
					init={getStore(frmNm)?.["status"]} 
					label={"Status"} 
					width={500} 
					updChanges={(e)=>updFrm("status",e)}
				/>	
			</div>
			
			
			<div className="_dsplFlx spaceAround flxWrp"> 
				<div style={{margin:"30px 10px 0 0"}}>
					<DateCalComponent 
						init={getStore(frmNm)?.["dateOfEntry"]} 
						label={"Date of Entry"}
						updDate={(e)=>updFrm("dateOfEntry",e)}
					/>
				</div>
				<div style={{margin:"30px 10px 0 0"}}>
					<DateCalComponent 
						init={getStore(frmNm)?.["dateOfLeft"]} 
						label={"Date of Left"}
						updDate={(e)=>updFrm("dateOfLeft",e)}
					/>
				</div>
			</div>
			{diff?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={print}/>
						
					</div>
				</div>
			):<div className="card"/>}


		</div>
	)

}






